### 3. Rendering Benchmarks
```rust
fn bench_rendering(c: &mut Criterion) {
    let mut group = c.benchmark_group("lipgloss/rendering");

    let simple_style = Style::new().foreground(Color::rgb(255, 0, 0));
    let complex_style = Style::new()
        .foreground(Color::rgb(255, 0, 0))
        .background(Color::rgb(0, 0, 255))
        .bold(true)
        .padding(1, 2, 1, 2)
        .border(Border::rounded());

    // Short text
    group.bench_function("render/short/simple", |b| {
        b.iter(|| black_box(simple_style.render("Hello")))
    });

    group.bench_function("render/short/complex", |b| {
        b.iter(|| black_box(complex_style.render("Hello")))
    });

    // Medium text (typical line)
    let medium = "x".repeat(80);
    group.throughput(Throughput::Bytes(80));
    group.bench_function("render/medium/simple", |b| {
        b.iter(|| black_box(simple_style.render(&medium)))
    });

    // Long text (full screen)
    let long = "x".repeat(4000);
    group.throughput(Throughput::Bytes(4000));
    group.bench_function("render/long/simple", |b| {
        b.iter(|| black_box(simple_style.render(&long)))
    });

    group.finish();
}
