```rust
#[cfg(test)]
mod derive_e2e_tests {
    use bubbletea_macros::Model;
    use bubbletea::{Program, Cmd};

    #[derive(Model)]
    struct Counter {
        #[model(state)]
        count: i32,
    }

    #[derive(Debug, Clone)]
    enum CounterMsg {
        Increment,
        Decrement,
        Reset,
    }

    impl Counter {
        fn update(&mut self, msg: CounterMsg) -> Cmd<CounterMsg> {
            match msg {
                CounterMsg::Increment => self.count += 1,
                CounterMsg::Decrement => self.count -= 1,
                CounterMsg::Reset => self.count = 0,
            }
            Cmd::none()
        }

        fn view(&self) -> String {
            format!("Count: {}", self.count)
        }
    }

    #[test]
    fn test_counter_app_full_lifecycle() {
        let mut app = Counter { count: 0 };

        // Test init() from derive macro
        let init_cmd = app.init();
        assert!(init_cmd.is_none(), "Default init should return None");

        // Test update cycle
        app.update(CounterMsg::Increment);
        assert_eq!(app.count, 1);

        app.update(CounterMsg::Increment);
        app.update(CounterMsg::Increment);
        assert_eq!(app.count, 3);

        app.update(CounterMsg::Decrement);
        assert_eq!(app.count, 2);

        // Test view
        let view = app.view();
        assert!(view.contains("2"));
    }
}
```

### 2. Todo Application E2E Test
```rust
#[derive(Model)]
#[model(init = "initialize")]
struct TodoApp {
    #[model(state)]
    items: Vec<TodoItem>,
    #[model(state)]
    selected: usize,
    #[model(state)]
    input_mode: bool,
    input_buffer: String, // Not marked as state - doesn't trigger re-render
}

#[derive(Clone)]
struct TodoItem {
    text: String,
    completed: bool,
}

#[derive(Debug, Clone)]
enum TodoMsg {
    Add(String),
    Toggle(usize),
    Delete(usize),
    SelectNext,
    SelectPrev,
    EnterInputMode,
    ExitInputMode,
    Loaded(Vec<TodoItem>),
}

impl TodoApp {
    fn initialize(&self) -> Cmd<TodoMsg> {
        // Custom init that loads saved todos
        Cmd::perform(
            async { load_todos_from_storage().await },
            TodoMsg::Loaded,
        )
    }

    fn update(&mut self, msg: TodoMsg) -> Cmd<TodoMsg> {
        match msg {
            TodoMsg::Add(text) => {
                self.items.push(TodoItem { text, completed: false });
                self.input_mode = false;
            }
            TodoMsg::Toggle(idx) => {
                if let Some(item) = self.items.get_mut(idx) {
                    item.completed = !item.completed;
                }
            }
            TodoMsg::Delete(idx) => {
                if idx < self.items.len() {
                    self.items.remove(idx);
                }
            }
            TodoMsg::SelectNext => {
                if self.selected < self.items.len().saturating_sub(1) {
                    self.selected += 1;
                }
            }
            TodoMsg::SelectPrev => {
                self.selected = self.selected.saturating_sub(1);
            }
            TodoMsg::EnterInputMode => self.input_mode = true,
            TodoMsg::ExitInputMode => self.input_mode = false,
            TodoMsg::Loaded(items) => self.items = items,
        }
        Cmd::none()
    }

    fn view(&self) -> String {
        let mut output = String::from("Todo List\n\n");

        for (i, item) in self.items.iter().enumerate() {
            let checkbox = if item.completed { "[x]" } else { "[ ]" };
            let cursor = if i == self.selected { ">" } else { " " };
            output.push_str(&format!("{} {} {}\n", cursor, checkbox, item.text));
        }

        output
    }
}

#[test]
fn test_todo_app_with_custom_init() {
    let mut app = TodoApp {
        items: vec![],
        selected: 0,
        input_mode: false,
        input_buffer: String::new(),
    };

    // Custom init should return a command
    let init_cmd = app.init();
    assert!(init_cmd.is_some(), "Custom init should return command");

    // Simulate loaded data
    app.update(TodoMsg::Loaded(vec![
        TodoItem { text: "Task 1".into(), completed: false },
        TodoItem { text: "Task 2".into(), completed: true },
    ]));

    assert_eq!(app.items.len(), 2);

    // Test view renders correctly
    let view = app.view();
    assert!(view.contains("Task 1"));
    assert!(view.contains("[x]")); // Completed item
}
```

