```rust
#[derive(Model)]
#[model(message = "FormMsg")]
struct RegistrationForm {
    #[model(state)]
    name: String,
    #[model(state)]
    email: String,
    #[model(state)]
    password: String,
    #[model(state)]
    errors: Vec<String>,
    #[model(state)]
    submitted: bool,
}

#[derive(Debug, Clone)]
enum FormMsg {
    SetName(String),
    SetEmail(String),
    SetPassword(String),
    Submit,
    ValidationError(Vec<String>),
    SubmitSuccess,
}

impl RegistrationForm {
    fn update(&mut self, msg: FormMsg) -> Cmd<FormMsg> {
        match msg {
            FormMsg::SetName(n) => self.name = n,
            FormMsg::SetEmail(e) => self.email = e,
            FormMsg::SetPassword(p) => self.password = p,
            FormMsg::Submit => {
                let errors = self.validate();
                if errors.is_empty() {
                    return Cmd::perform(
                        async { submit_form().await },
                        |_| FormMsg::SubmitSuccess,
                    );
                } else {
                    self.errors = errors;
                }
            }
            FormMsg::ValidationError(e) => self.errors = e,
            FormMsg::SubmitSuccess => self.submitted = true,
        }
        Cmd::none()
    }

    fn validate(&self) -> Vec<String> {
        let mut errors = Vec::new();
        if self.name.len() < 2 {
            errors.push("Name too short".into());
        }
        if !self.email.contains('@') {
            errors.push("Invalid email".into());
        }
        if self.password.len() < 8 {
            errors.push("Password too short".into());
        }
        errors
    }

    fn view(&self) -> String {
        let mut output = String::from("Registration Form\n\n");
        output.push_str(&format!("Name: {}\n", self.name));
        output.push_str(&format!("Email: {}\n", self.email));
        output.push_str("Password: ****\n");

        if !self.errors.is_empty() {
            output.push_str("\nErrors:\n");
            for err in &self.errors {
                output.push_str(&format!("- {}\n", err));
            }
        }

        if self.submitted {
            output.push_str("\nSubmitted successfully!");
        }

        output
    }
}

#[test]
fn test_form_validation_flow() {
    let mut form = RegistrationForm {
        name: String::new(),
        email: String::new(),
        password: String::new(),
        errors: vec![],
        submitted: false,
    };

    // Submit empty form - should fail validation
    form.update(FormMsg::Submit);
    assert_eq!(form.errors.len(), 3, "Should have 3 validation errors");

    // Fill in valid data
    form.update(FormMsg::SetName("John Doe".into()));
    form.update(FormMsg::SetEmail("john@example.com".into()));
    form.update(FormMsg::SetPassword("securepass123".into()));
    form.errors.clear();

    // Submit valid form
    let cmd = form.update(FormMsg::Submit);
    assert!(cmd.is_some(), "Valid form should trigger async submit");

    // Verify view
    let view = form.view();
    assert!(view.contains("John Doe"));
    assert!(view.contains("john@example.com"));
}
```

