#[derive(Model)]
#[model(init = "fetch_data")]
struct DataLoader {
    #[model(state)]
    data: Option<String>,
    #[model(state)]
    loading: bool,
    #[model(state)]
    error: Option<String>,
}

impl DataLoader {
    fn fetch_data(&self) -> Cmd<LoaderMsg> {
        Cmd::batch(vec![
            Cmd::message(LoaderMsg::StartLoading),
            Cmd::perform(
                async { fetch_from_api().await },
                |result| match result {
                    Ok(data) => LoaderMsg::DataLoaded(data),
                    Err(e) => LoaderMsg::Error(e.to_string()),
                },
            ),
        ])
    }
}

#[test]
fn test_async_loading_pattern() {
    let mut loader = DataLoader {
        data: None,
        loading: false,
        error: None,
    };

    // Init should return batch command
    let cmd = loader.init();
    assert!(cmd.is_some());

    // Simulate loading started
    loader.update(LoaderMsg::StartLoading);
    assert!(loader.loading);

    // Simulate data loaded
    loader.update(LoaderMsg::DataLoaded("API Response".into()));
    assert!(!loader.loading);
    assert_eq!(loader.data, Some("API Response".into()));
}
