## Objective
Implement PTY allocation and terminal session handling to support interactive terminal sessions over SSH.

## Implementation Details

### PTY Allocation
```rust
use portable_pty::{native_pty_system, PtySize, PtySystem};

pub struct PtySession {
    master: Box<dyn MasterPty + Send>,
    child: Box<dyn Child + Send + Sync>,
    size: PtySize,
}

impl PtySession {
    pub fn new(
        term: &str,
        cols: u16,
        rows: u16,
        command: Option<&str>,
    ) -> Result<Self> {
        log::debug!("Allocating PTY: term={}, size={}x{}", term, cols, rows);

        let pty_system = native_pty_system();
        let size = PtySize {
            rows,
            cols,
            pixel_width: 0,
            pixel_height: 0,
        };

        let pair = pty_system.openpty(size)?;

        let cmd = CommandBuilder::new(command.unwrap_or("/bin/sh"));
        cmd.env("TERM", term);

        let child = pair.slave.spawn_command(cmd)?;

        log::info!("PTY session created with PID {}", child.process_id());

        Ok(Self {
            master: pair.master,
            child,
            size,
        })
    }

    pub fn resize(&mut self, cols: u16, rows: u16) -> Result<()> {
        log::debug!("Resizing PTY to {}x{}", cols, rows);
        self.size = PtySize { rows, cols, ..self.size };
        self.master.resize(self.size)?;
        Ok(())
    }

    pub fn reader(&self) -> Box<dyn Read + Send> {
        self.master.try_clone_reader().unwrap()
    }

    pub fn writer(&self) -> Box<dyn Write + Send> {
        self.master.take_writer().unwrap()
    }
}
```

