### russh Handler Integration
```rust
impl russh::server::Handler for ConnectionHandler {
    async fn pty_request(
        &mut self,
        channel: ChannelId,
        term: &str,
        col_width: u32,
        row_height: u32,
        pix_width: u32,
        pix_height: u32,
        modes: &[(Pty, u32)],
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        log::info!(
            "PTY request: term={}, size={}x{}", 
            term, col_width, row_height
        );

        let pty_session = PtySession::new(
            term,
            col_width as u16,
            row_height as u16,
            None,
        )?;

        self.channels.insert(channel, ChannelState::Pty(pty_session));
        session.request_success();
        Ok(())
    }

    async fn window_change_request(
        &mut self,
        channel: ChannelId,
        col_width: u32,
        row_height: u32,
        pix_width: u32,
        pix_height: u32,
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        log::debug!("Window change: {}x{}", col_width, row_height);

        if let Some(ChannelState::Pty(pty)) = self.channels.get_mut(&channel) {
            pty.resize(col_width as u16, row_height as u16)?;
        }
        Ok(())
    }

    async fn data(
        &mut self,
        channel: ChannelId,
        data: &[u8],
        session: &mut Session,
    ) -> Result<(), Self::Error> {
        // Forward data to PTY
        if let Some(ChannelState::Pty(pty)) = self.channels.get_mut(&channel) {
            pty.writer().write_all(data)?;
        }
        Ok(())
    }
}
```

### PTY Output Forwarding
```rust
async fn forward_pty_output(
    mut reader: Box<dyn Read + Send>,
    handle: Handle,
    channel: ChannelId,
) {
    let mut buf = [0u8; 4096];
    loop {
        match reader.read(&mut buf) {
            Ok(0) => break, // EOF
            Ok(n) => {
                if handle.data(channel, CryptoVec::from_slice(&buf[..n])).await.is_err() {
                    break;
                }
            }
            Err(e) => {
                log::warn!("PTY read error: {}", e);
                break;
            }
        }
    }
    log::debug!("PTY output forwarding ended for channel {:?}", channel);
}
```

