proptest! {
    /// Property: CSI sequences roundtrip correctly
    #[test]
    fn csi_roundtrip(
        csi in arb_csi_sequence()
    ) {
        let bytes = csi.to_bytes();
        let parsed = CsiParser::parse(&bytes);

        prop_assert!(parsed.is_some());
        let (parsed_csi, consumed) = parsed.unwrap();
        prop_assert_eq!(consumed, bytes.len());

        let reserialized = parsed_csi.to_bytes();
        prop_assert_eq!(bytes, reserialized, "Canonical CSI should roundtrip exactly");
    }

    /// Property: SGR sequences roundtrip correctly
