    fn sgr_roundtrip(
        sgr in arb_sgr_sequence()
    ) {
        let bytes = sgr.to_bytes();
        let parsed = SgrParser::parse(&bytes);

        prop_assert!(parsed.is_some());
        let (params, consumed) = parsed.unwrap();
        prop_assert_eq!(consumed, bytes.len());

        let reserialized = SgrSerializer::serialize(&params);

        // Re-parse and compare semantically
        let (reparsed_params, _) = SgrParser::parse(&reserialized).unwrap();
        prop_assert_eq!(params, reparsed_params);
    }
}
