#[cfg(test)]
mod middleware_tests {
    use super::*;

    struct CountingMiddleware {
        counter: Arc<AtomicUsize>,
    }

    #[async_trait]
    impl Middleware for CountingMiddleware {
        async fn handle(&self, ctx: &mut Context, next: Next<'_>) -> Result<(), WishError> {
            self.counter.fetch_add(1, Ordering::SeqCst);
            next.run(ctx).await
        }
    }

    #[tokio::test]
    async fn test_middleware_chain_order() {
        let order = Arc::new(Mutex::new(Vec::new()));

        let chain = MiddlewareChain::new()
            .use_middleware(OrderTracker::new("first", order.clone()))
            .use_middleware(OrderTracker::new("second", order.clone()))
            .use_middleware(OrderTracker::new("third", order.clone()));

        let mut ctx = Context::test_context();
        chain.execute(&mut ctx, &NoOpHandler).await.unwrap();

        let order = order.lock().await;
        assert_eq!(*order, vec!["first", "second", "third"]);
    }

    #[tokio::test]
    async fn test_middleware_short_circuit() {
        let counter = Arc::new(AtomicUsize::new(0));

        let chain = MiddlewareChain::new()
            .use_middleware(CountingMiddleware { counter: counter.clone() })
            .use_middleware(RejectingMiddleware)  // This rejects
            .use_middleware(CountingMiddleware { counter: counter.clone() });

        let mut ctx = Context::test_context();
        let result = chain.execute(&mut ctx, &NoOpHandler).await;

        assert!(result.is_err());
        assert_eq!(counter.load(Ordering::SeqCst), 1); // Second never reached
    }

    #[tokio::test]
    async fn test_rate_limit_middleware() {
        let middleware = RateLimitMiddleware::new(2, Duration::from_secs(60));
        let mut ctx = Context::test_context();

        // First two should pass
        assert!(middleware.handle(&mut ctx, Next::terminal()).await.is_ok());
        assert!(middleware.handle(&mut ctx, Next::terminal()).await.is_ok());

        // Third should be rate limited
        assert!(matches!(
            middleware.handle(&mut ctx, Next::terminal()).await,
            Err(WishError::RateLimited)
        ));
    }
}
