+	for n := 1; n <= 6; n++ {
+		sb.WriteString(strings.Repeat("#", n))
+		sb.WriteString(fmt.Sprintf(" Header Level %d\n\n", n))
+	}
+	headers := strings.Repeat(sb.String(), 100)
+	b.ResetTimer()
+	for i := 0; i < b.N; i++ {
+		_, _ = r.Render(headers)
+	}
